using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(IHttpClientFactory httpClientFactory, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a list of posts, optionally filtered by user ID.")]
    public async Task<string> GetPosts(
        [Description("Filter posts by this user ID (optional)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("api");
        var path = userId.HasValue ? $"/posts?userId={userId}" : "/posts";

        logger.LogInformation("Fetching posts from {Path}", path);
        var json = await client.GetStringAsync(path, cancellationToken);

        using var doc = JsonDocument.Parse(json);
        var posts = doc.RootElement.EnumerateArray()
            .Select(p => new
            {
                id = p.GetProperty("id").GetInt32(),
                title = p.GetProperty("title").GetString(),
                userId = p.GetProperty("userId").GetInt32()
            });

        return JsonSerializer.Serialize(posts, JsonOptions);
    }

    [McpServerTool, Description("Get a single post by its ID.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post to retrieve")] int id,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("api");

        logger.LogInformation("Fetching post {Id}", id);
        var response = await client.GetAsync($"/posts/{id}", cancellationToken);

        if (!response.IsSuccessStatusCode)
            return $"Error: post {id} not found (HTTP {(int)response.StatusCode})";

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Get all comments for a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to get comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("api");

        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var json = await client.GetStringAsync($"/posts/{postId}/comments", cancellationToken);

        using var doc = JsonDocument.Parse(json);
        var comments = doc.RootElement.EnumerateArray()
            .Select(c => new
            {
                id = c.GetProperty("id").GetInt32(),
                name = c.GetProperty("name").GetString(),
                email = c.GetProperty("email").GetString(),
                body = c.GetProperty("body").GetString()
            });

        return JsonSerializer.Serialize(comments, JsonOptions);
    }
}

